Please generate code to solve the following task:

给你一个 `m x n` 的二维整数数组 `grid` 和一个整数 `k`。你从左上角的单元格 `(0, 0)` 出发，目标是到达右下角的单元格 `(m - 1, n - 1)`。

有两种移动方式可用：

- **普通移动**：你可以从当前单元格 `(i, j)` 向右或向下移动，即移动到 `(i, j + 1)`（右）或 `(i + 1, j)`（下）。成本为目标单元格的值。
- **传送**：你可以从任意单元格 `(i, j)` 传送到任意满足 `grid[x][y] <= grid[i][j]` 的单元格 `(x, y)`；此移动的成本为 0。你最多可以传送 `k` 次。

返回从 `(0, 0)` 到达单元格 `(m - 1, n - 1)` 的 **最小** 总成本。



**示例 1:**

**输入:** grid = [[1,3,3],[2,5,4],[4,3,5]], k = 2

**输出:** 7

**解释:**

我们最初在 (0, 0)，成本为 0。

| 当前位置 | 移动            | 新位置   | 总成本      |
| -------- | --------------- | -------- | ----------- |
| `(0, 0)` | 向下移动        | `(1, 0)` | `0 + 2 = 2` |
| `(1, 0)` | 向右移动        | `(1, 1)` | `2 + 5 = 7` |
| `(1, 1)` | 传送到 `(2, 2)` | `(2, 2)` | `7 + 0 = 7` |

到达右下角单元格的最小成本是 7。

**示例 2:**

**输入:** grid = [[1,2],[2,3],[3,4]], k = 1

**输出:** 9

**解释:**

我们最初在 (0, 0)，成本为 0。

| 当前位置 | 移动     | 新位置   | 总成本      |
| -------- | -------- | -------- | ----------- |
| `(0, 0)` | 向下移动 | `(1, 0)` | `0 + 2 = 2` |
| `(1, 0)` | 向右移动 | `(1, 1)` | `2 + 3 = 5` |
| `(1, 1)` | 向下移动 | `(2, 1)` | `5 + 4 = 9` |

到达右下角单元格的最小成本是 9。



**提示:**

- `2 <= m, n <= 80`
- `m == grid.length`
- `n == grid[i].length`
- `0 <= grid[i][j] <= 10**4`
- `0 <= k <= 10`

======
You must strictly follow this signature:
solve: def grid(Array[Array[Long]]): Long, def k(Long): Long

Target language: Scala

Requirements:
1. You may include auxiliary/helper code before or after the required signature.
2. All import/include statements (e.g., `import` in Python, `#include` in C/C++) must be placed at the very top of the file.
3. Preserve the provided signature exactly as given. Do not modify parameter names, types, or return types.
4. Ensure the final code is complete, self-contained, and directly runnable.
5. Return ONLY the raw code. Do not include explanations, markdown backticks, or conversational text.

You are generating Scala code. You only need to generate the requested function. DO NOT generate the main method. DO NOT generate object/class.
The reference solution of that problem in C++ is 
#include <vector>
#include <priority_queue>
#include <utility>
#include <climits>

using namespace std;

long long solve(vector<vector<long long>> grid, long long k) {
    int m = grid.size();
    int n = grid[0].size();
    const long long INF = 1e18;

    // Precompute teleport lists
    vector<vector<vector<pair<int, int>>>> teleport_list(m, vector<vector<pair<int, int>>>(n));
    for (int i = 0; i < m; ++i) {
        for (int j = 0; j < n; ++j) {
            long long current_val = grid[i][j];
            for (int x = 0; x < m; ++x) {
                for (int y = 0; y < n; ++y) {
                    if (grid[x][y] <= current_val) {
                        teleport_list[i][j].push_back({x, y});
                    }
                }
            }
        }
    }

    // Initialize distance array
    vector<vector<vector<long long>>> dist(m, vector<vector<long long>>(n, vector<long long>(k+1, INF)));
    dist[0][0][0] = 0;

    // Priority queue: (cost, i, j, t)
    priority_queue<tuple<long long, int, int, int>, vector<tuple<long long, int, int, int>>, greater<>> pq;
    pq.push({0, 0, 0, 0});

    while (!pq.empty()) {
        auto [cost, i, j, t] = pq.top();
        pq.pop();

        // If we have already found a better path, skip
        if (cost > dist[i][j][t]) continue;

        // Check if we have reached the destination
        if (i == m-1 && j == n-1) {
            return cost;
        }

        // Regular moves: right and down
        if (j+1 < n) {
            long long new_cost = cost + grid[i][j+1];
            if (new_cost < dist[i][j+1][t]) {
                dist[i][j+1][t] = new_cost;
                pq.push({new_cost, i, j+1, t});
            }
        }
        if (i+1 < m) {
            long long new_cost = cost + grid[i+1][j];
            if (new_cost < dist[i+1][j][t]) {
                dist[i+1][j][t] = new_cost;
                pq.push({new_cost, i+1, j, t});
            }
        }

        // Teleportation
        if (t < k) {
            for (auto [x, y] : teleport_list[i][j]) {
                long long new_cost = cost;
                if (new_cost < dist[x][y][t+1]) {
                    dist[x][y][t+1] = new_cost;
                    pq.push({new_cost, x, y, t+1});
                }
            }
        }
    }

    return -1;
}

