import scala.collection.mutable.PriorityQueue

def solve(grid: Array[Array[Long]], k: Long): Long = {
    val m = grid.length
    val n = grid(0).length
    val INF = 1e18.toLong
    val teleportList = Array.ofDim[List[(Int, Int)]](m, n)
    for (i <- 0 until m; j <- 0 until n) {
        teleportList(i)(j) = (for {
            x <- 0 until m
            y <- 0 until n
            if grid(x)(y) <= grid(i)(j)
        } yield (x, y)).toList
    }
    val dist = Array.ofDim[Long](m, n, k + 1)
    for (i <- 0 until m; j <- 0 until n; t <- 0 until k + 1) {
        dist(i)(j)(t) = INF
    }
    dist(0)(0)(0) = 0L
    val pq = PriorityQueue[(Long, Int, Int, Int)]()
    pq += (0L, 0, 0, 0)
    while (pq.nonEmpty) {
        val (cost, i, j, t) = pq.dequeue()
        if (i == m - 1 && j == n - 1) return cost
        if (cost > dist(i)(j)(t)) {
            // Skip this state as a better path has already been found
            continue
        }
        // Regular moves: right and down
        if (j + 1 < n) {
            val newCost = cost + grid(i)(j + 1)
            if (newCost < dist(i)(j + 1)(t)) {
                dist(i)(j + 1)(t) = newCost
                pq += (newCost, i, j + 1, t)
            }
        }
        if (i + 1 < m) {
            val newCost = cost + grid(i + 1)(j)
            if (newCost < dist(i + 1)(j)(t)) {
                dist(i + 1)(j)(t) = newCost
                pq += (newCost, i + 1, j, t)
            }
        }
        // Teleportation
        if (t < k) {
            for ((x, y) <- teleportList(i)(j)) {
                if (cost < dist(x)(y)(t + 1)) {
                    dist(x)(y)(t + 1) = cost
                    pq += (cost, x, y, t + 1)
                }
            }
        }
    }
    -1
}
