  val teleportList = Array.ofDim[Array[(Int, Int)]](m, n)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      val current = grid(i)(j)
      val list = ListBuffer[(Int, Int)]()
      for (x <- 0 until m) {
        for (y <- 0 until n) {
